import{_ as e,o as i,c as a,ao as l}from"./chunks/framework.hY-gA2uj.js";const h=JSON.parse('{"title":"Comparison with rvinecopulib / vinecopulib","description":"","frontmatter":{},"headers":[],"relativePath":"comparison/rvinecopulib.md","filePath":"comparison/rvinecopulib.md","lastUpdated":null}'),r={name:"comparison/rvinecopulib.md"};function o(n,t,s,d,c,g){return i(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="Comparison-with-rvinecopulib-/-vinecopulib" tabindex="-1">Comparison with rvinecopulib / vinecopulib <a class="header-anchor" href="#Comparison-with-rvinecopulib-/-vinecopulib" aria-label="Permalink to &quot;Comparison with rvinecopulib / vinecopulib {#Comparison-with-rvinecopulib-/-vinecopulib}&quot;">​</a></h1><p><code>rvinecopulib</code> is the R interface to <code>vinecopulib</code>, a header-only C++ library for vine copula models. It is a mature statistical modeling package with high-performance algorithms, parameter estimation, model selection, simulation, visualization, and support for nonparametric and multi-parameter families.</p><p><code>VineCopulas.jl</code> has a different first goal: provide a native Julia construction and evaluation core that composes pair-copulas from <code>Copulas.jl</code>.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Feature</th><th style="text-align:right;"><code>VineCopulas.jl</code> v0.1</th><th style="text-align:right;"><code>rvinecopulib</code> / <code>vinecopulib</code></th></tr></thead><tbody><tr><td style="text-align:right;">Language</td><td style="text-align:right;">Julia</td><td style="text-align:right;">C++ core, R interface, Python interface</td></tr><tr><td style="text-align:right;">Main scope</td><td style="text-align:right;">Explicit construction, evaluation, simulation, transforms</td><td style="text-align:right;">Full statistical modeling workflow</td></tr><tr><td style="text-align:right;">C-vines / D-vines</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">R-vines</td><td style="text-align:right;">Partial/experimental</td><td style="text-align:right;">Mature</td></tr><tr><td style="text-align:right;">Density and simulation</td><td style="text-align:right;">Yes</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">h-functions and inverse h-functions</td><td style="text-align:right;">Yes, via Julia API</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">Automatic pair-copula fitting</td><td style="text-align:right;">Not yet</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">Automatic family selection</td><td style="text-align:right;">Not yet</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">Automatic structure selection</td><td style="text-align:right;">Not yet</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">Automatic truncation selection</td><td style="text-align:right;">Not yet</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">Nonparametric pair-copulas</td><td style="text-align:right;">Not part of stable v0.1</td><td style="text-align:right;">Yes</td></tr><tr><td style="text-align:right;">Discrete variables</td><td style="text-align:right;">Not part of stable v0.1</td><td style="text-align:right;">Supported in rvinecopulib</td></tr><tr><td style="text-align:right;">Extensibility with <code>Copulas.jl</code></td><td style="text-align:right;">Main design goal</td><td style="text-align:right;">Not the goal</td></tr><tr><td style="text-align:right;">Bayesian/probabilistic Julia workflows</td><td style="text-align:right;">Natural future direction</td><td style="text-align:right;">External to the package</td></tr></tbody></table><p>The honest positioning is therefore:</p><ul><li><p>use <code>rvinecopulib</code> when you need a mature production-ready fitting and selection workflow today;</p></li><li><p>use <code>VineCopulas.jl</code> when you want explicit native Julia vine objects, direct integration with <code>Copulas.jl</code>, transparent conditional primitives, and a research-friendly base for future Julia workflows.</p></li></ul><p>No speed superiority is claimed for <code>VineCopulas.jl</code> v0.1. Benchmarking against C++ belongs to a later performance milestone.</p>',7)])])}const u=e(r,[["render",o]]);export{h as __pageData,u as default};
